from __future__ import annotations

import argparse
import json
import os
import re
import subprocess
from datetime import datetime
from pathlib import Path

from runtime_state_schema import build_precheck_runtime_truth, get_runtime_truth

ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = ROOT / "research" / "reports"
WORKSPACE_ROOT = ROOT.parents[1] if len(ROOT.parents) >= 2 else ROOT
STATE_PATH = Path(
    str(
        os.environ.get("PREMARKET_PRECHECK_STATE_PATH")
        or (WORKSPACE_ROOT / "memory" / "premarket_precheck_state.json")
    )
)


def now_shanghai() -> datetime:
    return datetime.now()


def load_state() -> dict:
    if not STATE_PATH.exists():
        return {}
    try:
        return json.loads(STATE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {}


def save_state(payload: dict) -> None:
    STATE_PATH.parent.mkdir(parents=True, exist_ok=True)
    STATE_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def is_trading_day(date_str: str) -> bool:
    """
    交易日判断：优先用腾讯行情 API，API 异常时降级为工作日（周一~五）判断。
    """
    try:
        date_obj = datetime.strptime(date_str, "%Y-%m-%d")
        weekday_fallback = date_obj.weekday() < 5
    except Exception:
        weekday_fallback = False

